import React from "react";

function FacultySubmissionViewer({

    open,

    submission,

    onClose

}) {

    if (!open || !submission) {

        return null;

    }

    return (

        <div
            style={{
                position: "fixed",
                inset: 0,
                background: "rgba(0,0,0,.55)",
                display: "flex",
                justifyContent: "center",
                alignItems: "center",
                zIndex: 9999
            }}
        >

            <div
                style={{
                    width: "92%",
                    maxWidth: "1200px",
                    maxHeight: "92vh",
                    overflowY: "auto",
                    background: "#fff",
                    borderRadius: "18px",
                    padding: "30px",
                    boxShadow: "0 15px 40px rgba(0,0,0,.25)"
                }}
            >

                {/* Header */}

                <div
                    style={{
                        display: "flex",
                        justifyContent: "space-between",
                        alignItems: "center",
                        marginBottom: "25px"
                    }}
                >

                    <h2
                        style={{
                            margin: 0,
                            color: "#1e3a8a"
                        }}
                    >

                        Faculty Submission Details

                    </h2>

                    <button
                        onClick={onClose}
                        style={{
                            background: "#dc2626",
                            color: "#fff",
                            border: "none",
                            padding: "10px 18px",
                            borderRadius: "8px",
                            cursor: "pointer",
                            fontWeight: "600"
                        }}
                    >

                        Close

                    </button>

                </div>

                {/* Faculty Details */}

                <div
                    style={{
                        background: "#f8fafc",
                        border: "1px solid #e5e7eb",
                        borderRadius: "12px",
                        padding: "20px",
                        marginBottom: "25px"
                    }}
                >

                    <h3
                        style={{
                            marginTop: 0,
                            color: "#2563eb"
                        }}
                    >

                        Faculty Information

                    </h3>

                    <table
                        style={{
                            width: "100%"
                        }}
                    >

                        <tbody>

                            <tr>

                                <td><b>Name</b></td>

                                <td>{submission.submittedByName}</td>

                                <td><b>Email</b></td>

                                <td>{submission.submittedByEmail}</td>

                            </tr>

                            <tr>

                                <td><b>Department</b></td>

                                <td>{submission.department}</td>

                                <td><b>Quarter</b></td>

                                <td>{submission.quarter}</td>

                            </tr>

                            <tr>

                                <td><b>Status</b></td>

                                <td>{submission.status}</td>

                                <td><b>Answered</b></td>

                                <td>

                                    {submission.answeredCount}

                                    /

                                    {submission.totalQuestions}

                                </td>

                            </tr>

                        </tbody>

                    </table>

                </div>

                {/* Questions Start */}

                <h3
                    style={{
                        color: "#2563eb"
                    }}
                >

                    Questions & Answers

                </h3>

            </div>

        </div>

    );


}

export default FacultySubmissionViewer;
